        # Check for numeric patterns (including negatives and decimals)
        num_match = re.search(r'-?\d+\.?\d*', s)
        if num_match:
            num_str = num_match.group(0)
            if '.' in num_str:
                return float(num_str)
            return int(num_str)

        # Check for special cases like 'X' (could be 10 in some contexts)
        if 'x' in s.lower():
            return 10  # Assuming X represents 10 (like iPhone X)

        return s

    def sort_key(s: str):
        extracted = extract_number(s)
        if isinstance(extracted, (int, float)):
            return (0, extracted, s)
        else:
            return (1, s)

    return sorted(strings, key=sort_key)

